/// 2000-FIND-NEXT-AUTH-SUMMARY
fn p_2000_find_next_auth_summary(state: &mut ProgramState) {
    if state.prm_info.p_debug_flag == "Y" {
        println!("{}{}", "DEBUG: AUTH SMRY READ : ", state.ws_variables.ws_no_sumry_read);
    }
    match state._unresolved_dibstat.as_str() {
        "  " => {
            state.ws_variables.ws_end_of_authdb_flag = "N".into();
            state.ws_variables.ws_no_sumry_read += 1 as i32;
            state.ws_variables.ws_auth_smry_proc_cnt += 1 as u32;
            state.ws_variables.ws_curr_app_id = i64::from(state.pending_auth_summary.pa_acct_id) as u64;
        }
        "GB" => {
            state.ws_variables.ws_end_of_authdb_flag = "Y".into();
        }
        _ => {
            // SKIP: unresolved display ref
            println!("{}{}", "SUMMARY READ BEFORE ABEND :", state.ws_variables.ws_no_sumry_read);
            p_9999_abend(state);
        }
    }
}

/// 2000-EXIT
fn p_2000_exit(state: &mut ProgramState) {
}

/// 3000-FIND-NEXT-AUTH-DTL
fn p_3000_find_next_auth_dtl(state: &mut ProgramState) {
    if state.prm_info.p_debug_flag == "Y" {
        println!("{}{}", "DEBUG: AUTH DTL READ : ", state.ws_variables.ws_no_dtl_read);
    }
    match state._unresolved_dibstat.as_str() {
        "  " => {
            state.ws_variables.ws_more_auths_flag = "Y".into();
            state.ws_variables.ws_no_dtl_read += 1 as i32;
        }
        "GE" | "GB" => {
            state.ws_variables.ws_more_auths_flag = "N".into();
        }
        _ => {
            // SKIP: unresolved display ref
            println!("{}{}", "SUMMARY AUTH APP ID      :", state.pending_auth_summary.pa_acct_id);
            println!("{}{}", "DETAIL READ BEFORE ABEND :", state.ws_variables.ws_no_dtl_read);
            p_9999_abend(state);
        }
    }
}

